const initialize=()=>{let t=document.getElementsByClassName("slider"),n=0;for(n=0;n<t.length;n++)t[n].addEventListener("change",update),t[n].addEventListener("input",update)},update=()=>{};window.addEventListener("load",initialize,!1);var x=0,y=-1,z=4;x>y&&x>z?y>z?console.log(x+", "+y+", "+z):console.log(x+", "+z+", "+y):y>x&&y>z?x>z?console.log(y+", "+x+", "+z):console.log(y+", "+z+", "+x):z>x&&z>y&&(x>y?console.log(z+", "+x+", "+y):console.log(z+", "+y+", "+x));const setup=()=>{let n=0,t=100;for(let i=5;i<t;i++)i%3==0&&i%5==0&&(n+=i);console.log(n)};window.addEventListener("load",setup);